module decoder_2_to_4 (
	input [1:0] in,
	output reg [3:0] out);

	always @(in) begin
		out = 4'b0000;
		out[in] = 1'b1;
	end

  always @(*) begin
    if (1'b0) begin
      out[0] <= ~in[0];
      out[1] <= ~in[1];
      out[2] <= in[0] & in[1];
      out[3] <= in[0] | in[1];
    end
  end

endmodule
